/**
 * Facebook Pixel Event Listeners
 *
 * Uses the unified event system (pmw:*) with firing decisions.
 * Checks payload.firing.facebook.fire_browser before firing the browser pixel.
 *
 * @see https://developers.facebook.com/docs/meta-pixel/reference
 */

// Load pixel event
jQuery(document).on("pmw:load-pixels", () => {

	if (
		pmwDataLayer?.pixels?.facebook?.pixel_id
		&& !pmwDataLayer?.pixels?.facebook?.loaded
		&& !pmw.doesUrlContainPatterns(pmwDataLayer?.pixels?.facebook?.exclusion_patterns)
	) {
		if (pmw.consent.canPixelBeFired("marketing", "Facebook")) pmw.loadFacebookPixel();
	}
});

// PageView event
// https://developers.facebook.com/docs/meta-pixel/reference
jQuery(document).on("pmw:pixel:page-view", (event, payload) => {

	try {
		if (pmw.canNotFireFbq()) return;
		if (!pmw.shouldFireBrowserPixel(payload, "facebook")) return;

		const facebookData = payload.pixels?.facebook;
		if (!facebookData) {
			pmw.console.log("Facebook: No data in payload for page_view event");
			return;
		}

		fbq("track", facebookData.event_name, facebookData.custom_data, {
			eventID: facebookData.event_id,
		});
		// pmw.console.log("Facebook: PageView event sent", facebookData);

	} catch (error) {
		console.error(error);
	}
});

